INSERT INTO `lee_news` (`news_id`, `member_id`, `title`, `summary`, `content`, `status`, `created_at`, `updated_at`) VALUES
(1, 1, '李武略資料來源整理', '新增族譜與祭祀公業資料來源。', '整理李武略號殖春公派下相關網路來源。', 'published', '2026-01-10 09:00:00', '2026-01-10 09:00:00'),
(2, 2, '李良經資料欄位建立', '本名欄位已加入人物資料卡。', '本名李良經、號殖春、祖先李武略。', 'published', '2026-01-20 09:00:00', '2026-01-20 09:00:00'),
(3, 1, '族譜紀錄頁更新', '加入李武略號殖春公派下系統。', '族譜頁保留世系與來源欄位。', 'published', '2026-02-03 09:00:00', '2026-02-03 09:00:00'),
(4, 2, '祭祀公業資料更新', '加入統一編號 76645678。', '祭祀公業頁可管理公業與宗祠資料。', 'published', '2026-02-18 09:00:00', '2026-02-18 09:00:00'),
(5, 1, '宗祠大埕活動紀錄', '活動花絮頁加入宗祠活動。', '活動照片與影片未來由後台上傳。', 'draft', '2026-03-02 09:00:00', NULL),
(6, 2, '外水尾資料節點', '地區區塊加入外水尾。', '保留地區與資料節點欄位。', 'published', '2026-03-12 09:00:00', '2026-03-12 09:00:00'),
(7, 1, '古文書線索新增', '加入嘉慶十二年契約摘要。', '古文書需保留來源與查證日期。', 'published', '2026-04-01 09:00:00', '2026-04-01 09:00:00'),
(8, 2, '後台模組規劃完成', 'controller placeholder 已建立。', '後續可接 PHP CRUD。', 'draft', '2026-04-15 09:00:00', NULL);
