INSERT INTO `pages` (`id`, `wp_id`, `slug`, `title`, `subtitle`, `hero_image`, `meta_description`, `status`, `sort_order`, `created_at`, `updated_at`) VALUES
(1, 1121, 'home', '曾氏宗親會', '歡迎探索 曾氏宗親會 的深厚傳統與文化。從宗聖公的「孝」教誨，到三省吾身的深邃教導，我們傳承了數世紀的忠誠、信用和終身學習的核心價值。每一代的曾氏後裔都肩負著這些價值觀，不僅在家庭和社會中實踐，更希望透過此平台，讓更多人認識並感受到這些無價', 'https://tseng-clan.com/wp-content/uploads/2023/08/icon.png', '歡迎探索 曾氏宗親會 的深厚傳統與文化。從宗聖公的「孝」教誨，到三省吾身的深邃教導，我們傳承了數世紀的忠誠、信用和終身學習的核心價值。每一代的曾氏後裔都肩負著這些價值觀，不僅在家庭和社會中實踐，更希望透過此平台，讓更多人認識並感受到這些無價的教誨。', 'published', 1, '2023-08-17 12:19:16', '2024-03-15 17:01:02'),
(2, 1928, '沿革-2', '沿革', '曾氏的歷史源流 曾氏家族的歷史源遠流長，可追溯到明朝時期。家族始祖曾箴公，一路傳承至今已有超過六十代。在這漫長 […]', 'https://tseng-clan.com/wp-content/uploads/2023/08/about.jpg', '曾氏的歷史源流 曾氏家族的歷史源遠流長，可追溯到明朝時期。家族始祖曾箴公，一路傳承至今已有超過六十代。在這漫長 […]', 'published', 2, '2023-10-02 16:32:47', '2023-10-05 14:03:41'),
(3, 1950, '組織章程', '組織章程', '曾氏公親族會組織章程 穿越時代的輪迴，曾氏家族以不變的信念和堅定的決心，建立了一套完整的組織架構。這不僅是一份 […]', '', '曾氏公親族會組織章程 穿越時代的輪迴，曾氏家族以不變的信念和堅定的決心，建立了一套完整的組織架構。這不僅是一份 […]', 'published', 3, '2023-10-05 11:17:42', '2024-02-06 11:24:16'),
